import sys

def main():
    data = sys.stdin.read().split()
    if not data:
        return
    N = int(data[0])
    M = int(data[1])
    pieces = []
    index = 2
    for i in range(M):
        a = int(data[index])
        b = int(data[index + 1])
        index += 2
        pieces.append((a, b))

    R = set()
    C = set()
    S = set()
    D = set()

    for a, b in pieces:
        R.add(a)
        C.add(b)
        S.add(a + b)
        D.add(a - b)

    def len_sum(s, N):
        low = max(1, s - N)
        high = min(N, s - 1)
        if low > high:
            return 0
        return high - low + 1

    def len_diff(d, N):
        low = max(1, 1 + d)
        high = min(N, N + d)
        if low > high:
            return 0
        return high - low + 1

    A_size = len(R) * N
    B_size = len(C) * N
    C_size = sum(len_sum(s, N) for s in S)
    D_size = sum(len_diff(d, N) for d in D)

    AB = len(R) * len(C)

    AC = 0
    for s in S:
        low = max(1, s - N)
        high = min(N, s - 1)
        if low > high:
            continue
        count = 0
        for r in R:
            if low <= r <= high:
                count += 1
        AC += count

    AD = 0
    for d in D:
        low = max(1, d + 1)
        high = min(N, d + N)
        if low > high:
            continue
        count = 0
        for r in R:
            if low <= r <= high:
                count += 1
        AD += count

    BC = 0
    for s in S:
        low = max(1, s - N)
        high = min(N, s - 1)
        if low > high:
            continue
        count = 0
        for c in C:
            if low <= c <= high:
                count += 1
        BC += count

    BD = 0
    for d in D:
        low = max(1, 1 - d)
        high = min(N, N - d)
        if low > high:
            continue
        count = 0
        for c in C:
            if low <= c <= high:
                count += 1
        BD += count

    CD = 0
    for s in S:
        for d in D:
            if (s + d) % 2 != 0:
                continue
            i_val = (s + d) // 2
            j_val = (s - d) // 2
            if 1 <= i_val <= N and 1 <= j_val <= N:
                CD += 1

    ABC = 0
    for i in R:
        for j in C:
            if (i + j) in S:
                ABC += 1

    ABD = 0
    for i in R:
        for j in C:
            if (i - j) in D:
                ABD += 1

    ACD = 0
    for s in S:
        for d in D:
            if (s + d) % 2 != 0:
                continue
            i_val = (s + d) // 2
            j_val = (s - d) // 2
            if 1 <= i_val <= N and 1 <= j_val <= N and i_val in R:
                ACD += 1

    BCD = 0
    for s in S:
        for d in D:
            if (s + d) % 2 != 0:
                continue
            i_val = (s + d) // 2
            j_val = (s - d) // 2
            if 1 <= i_val <= N and 1 <= j_val <= N and j_val in C:
                BCD += 1

    ABCD = 0
    for i in R:
        for j in C:
            if (i + j) in S and (i - j) in D:
                ABCD += 1

    total_attacked = (A_size + B_size + C_size + D_size) - (AB + AC + AD + BC + BD + CD) + (ABC + ABD + ACD + BCD) - ABCD
    answer = N * N - total_attacked
    print(answer)

if __name__ == "__main__":
    main()
